import React, { useState, useCallback, useMemo, memo } from "react";
import Header from "../components/Layout/Header";
import Sidebar from "../components/Layout/Sidebar";
import Footer from "../components/Layout/Footer";
import Button from "../components/Shared/Button";
import Input from "../components/Shared/Input";
import ModalActualizacion from "../components/Modal/ModalActualizacion";
import { useObras } from "../context/ObraContext";
import { colorBarra, estadoLabel, formatearFechaHora } from "../utils/formatters";

const ESTADOS = [
  { value: "", label: "Todos los estados" },
  { value: "actualizada", label: "Actualizada" },
  { value: "en_progreso", label: "En progreso" },
  { value: "pendiente", label: "Pendiente" },
];

const BarraPct = memo(function BarraPct({ pct }) {
  return (
    <div className="flex items-center gap-2 min-w-[120px]">
      <div className="flex-1 rounded-full h-1.5 overflow-hidden" style={{ backgroundColor: "#F5F3F0" }}>
        <div
          className={`h-1.5 rounded-full ${colorBarra(pct)} transition-all duration-500`}
          style={{ width: `${pct}%` }}
        />
      </div>
      <span className="text-xs font-semibold w-9 text-right" style={{ color: "#2C2C2C" }}>{pct}%</span>
    </div>
  );
});

const BadgeEstado = memo(function BadgeEstado({ estado }) {
  const info = estadoLabel(estado);
  return <span className={`badge ${info.clase} text-xs`}>{info.icono} {info.label}</span>;
});

function getObraKey(obra, index) {
  return `${obra.direccion_general || "sin-direccion"}-${obra.programa || "sin-programa"}-${obra.nombre || "sin-nombre"}-${index}`;
}

function getProgramaResumen(obras) {
  const total = obras.length;
  const actualizadas = obras.filter((obra) => obra.estado === "actualizada").length;
  const promedio = total > 0
    ? Math.round(obras.reduce((acc, obra) => acc + Number(obra.porcentaje || 0), 0) / total)
    : 0;

  return { total, actualizadas, promedio };
}

export default function ListadoObras() {
  const {
    obras,
    obrasFiltradas,
    loading,
    busqueda, setBusqueda,
    filtroProg, setFiltroProg,
    filtroEst, setFiltroEst,
  } = useObras();

  const [obraModal, setObraModal] = useState(null);

  const abrirModal = useCallback((obra) => setObraModal(obra), []);
  const cerrarModal = useCallback(() => setObraModal(null), []);

  const programas = useMemo(() => {
    return [...new Set(
      obras
        .map((obra) => obra.programa)
        .filter(Boolean)
    )].sort((a, b) => a.localeCompare(b));
  }, [obras]);

  const groupedData = useMemo(() => {
    return obrasFiltradas.reduce((acc, obra) => {
      const dg = obra.direccion_general || "SIN DIRECCION";
      const programa = obra.programa || "SIN PROGRAMA";

      if (!acc[dg]) acc[dg] = {};
      if (!acc[dg][programa]) acc[dg][programa] = [];

      acc[dg][programa].push(obra);
      return acc;
    }, {});
  }, [obrasFiltradas]);

  const direcciones = useMemo(() => {
    return Object.entries(groupedData)
      .map(([direccion, programasMap]) => {
        const programasLista = Object.entries(programasMap)
          .map(([programa, obrasPrograma]) => ({
            programa,
            obras: obrasPrograma,
            resumen: getProgramaResumen(obrasPrograma),
          }))
          .sort((a, b) => a.programa.localeCompare(b.programa));

        const totalObras = programasLista.reduce((acc, item) => acc + item.obras.length, 0);
        const totalProgramas = programasLista.length;

        return {
          direccion,
          programas: programasLista,
          totalObras,
          totalProgramas,
        };
      })
      .sort((a, b) => a.direccion.localeCompare(b.direccion));
  }, [groupedData]);

  return (
    <div className="min-h-screen flex flex-col" style={{ backgroundColor: "#F5F3F0" }}>
      <Header />

      <div className="flex flex-1">
        <Sidebar />

        <main className="flex-1 px-4 sm:px-6 lg:px-8 py-6 max-w-7xl mx-auto w-full">
          <div className="mb-6 animate-fade-in">
            <h1 className="text-2xl font-bold" style={{ color: "#691C32" }}>Listado de obras</h1>
            <p className="text-sm mt-1" style={{ color: "#666666" }}>
              {obrasFiltradas.length} obra{obrasFiltradas.length !== 1 ? "s" : ""} en {direcciones.length} direcci{direcciones.length === 1 ? "on" : "ones"} generales
            </p>
          </div>

          <div
            className="bg-white rounded-xl p-4 mb-5 animate-fade-in"
            style={{ border: "1px solid #D4C4B0", boxShadow: "0 2px 8px rgba(0,0,0,0.06)" }}
          >
            <div className="flex flex-col lg:flex-row gap-3">
              <div className="flex-1">
                <Input
                  id="busqueda-obras"
                  placeholder="Buscar por nombre..."
                  value={busqueda}
                  onChange={(e) => setBusqueda(e.target.value)}
                  aria-label="Buscar obras por nombre"
                />
              </div>

              <select
                value={filtroProg}
                onChange={(e) => setFiltroProg(e.target.value)}
                className="px-3 py-2 text-sm rounded-lg bg-white focus:outline-none focus:ring-2 focus:ring-[#691C32] focus:border-[#691C32] transition-colors"
                style={{ border: "1px solid #D4C4B0", color: "#2C2C2C" }}
                aria-label="Filtrar por programa"
              >
                <option value="">Todos los programas</option>
                {programas.map((programa) => (
                  <option key={programa} value={programa}>{programa}</option>
                ))}
              </select>

              <select
                value={filtroEst}
                onChange={(e) => setFiltroEst(e.target.value)}
                className="px-3 py-2 text-sm rounded-lg bg-white focus:outline-none focus:ring-2 focus:ring-[#691C32] focus:border-[#691C32] transition-colors"
                style={{ border: "1px solid #D4C4B0", color: "#2C2C2C" }}
                aria-label="Filtrar por estado"
              >
                {ESTADOS.map((estado) => (
                  <option key={estado.value} value={estado.value}>{estado.label}</option>
                ))}
              </select>

              {(busqueda || filtroProg || filtroEst) && (
                <Button
                  variant="ghost"
                  size="md"
                  onClick={() => { setBusqueda(""); setFiltroProg(""); setFiltroEst(""); }}
                  aria-label="Limpiar todos los filtros"
                >
                  Limpiar
                </Button>
              )}
            </div>
          </div>

          {loading ? (
            <div className="flex items-center justify-center py-16">
              <div
                className="w-8 h-8 border-4 border-t-transparent rounded-full animate-spin"
                style={{ borderColor: "#691C32", borderTopColor: "transparent" }}
              />
            </div>
          ) : direcciones.length === 0 ? (
            <div
              className="text-center py-12 text-sm bg-white rounded-xl animate-fade-in"
              style={{ color: "#666666", border: "1px solid #D4C4B0" }}
            >
              No se encontraron obras con los filtros seleccionados.
            </div>
          ) : (
            <div className="space-y-4 animate-fade-in">
              {direcciones.map((direccion) => (
                <details
                  key={direccion.direccion}
                  open
                  className="bg-white rounded-2xl overflow-hidden"
                  style={{ border: "1px solid #D4C4B0", boxShadow: "0 4px 14px rgba(0,0,0,0.05)" }}
                >
                  <summary
                    className="list-none cursor-pointer px-5 py-4"
                    style={{ background: "linear-gradient(135deg, #691C32 0%, #8D2743 100%)", color: "#FFF8F1" }}
                  >
                    <div className="flex flex-col gap-3 lg:flex-row lg:items-center lg:justify-between">
                      <div>
                        <p className="text-xs uppercase tracking-[0.24em] opacity-80">Direccion General</p>
                        <h2 className="text-lg font-semibold mt-1">{direccion.direccion}</h2>
                      </div>
                      <div className="flex flex-wrap gap-2 text-xs">
                        <span className="px-3 py-1 rounded-full" style={{ backgroundColor: "rgba(255,248,241,0.16)" }}>
                          {direccion.totalProgramas} programa{direccion.totalProgramas !== 1 ? "s" : ""}
                        </span>
                        <span className="px-3 py-1 rounded-full" style={{ backgroundColor: "rgba(255,248,241,0.16)" }}>
                          {direccion.totalObras} obra{direccion.totalObras !== 1 ? "s" : ""}
                        </span>
                      </div>
                    </div>
                  </summary>

                  <div className="p-4 sm:p-5 space-y-4" style={{ backgroundColor: "#FFFCF8" }}>
                    {direccion.programas.map((programaItem) => (
                      <details
                        key={`${direccion.direccion}-${programaItem.programa}`}
                        className="rounded-2xl overflow-hidden"
                        style={{ border: "1px solid rgba(212,196,176,0.8)", backgroundColor: "#FFFFFF" }}
                      >
                        <summary className="list-none cursor-pointer px-4 py-4">
                          <div className="flex flex-col gap-3 xl:flex-row xl:items-center xl:justify-between">
                            <div>
                              <p className="text-xs uppercase tracking-[0.2em]" style={{ color: "#8B6E5A" }}>Programa</p>
                              <h3 className="text-base font-semibold mt-1" style={{ color: "#2C2C2C" }}>
                                {programaItem.programa}
                              </h3>
                            </div>
                            <div className="flex flex-wrap gap-2 text-xs">
                              <span
                                className="px-3 py-1 rounded-full"
                                style={{ backgroundColor: "#F5F3F0", color: "#5B4B3F" }}
                              >
                                {programaItem.resumen.total} obra{programaItem.resumen.total !== 1 ? "s" : ""}
                              </span>
                              <span
                                className="px-3 py-1 rounded-full"
                                style={{ backgroundColor: "#F5F3F0", color: "#5B4B3F" }}
                              >
                                {programaItem.resumen.actualizadas} actualizadas
                              </span>
                              <span
                                className="px-3 py-1 rounded-full"
                                style={{ backgroundColor: "#F5F3F0", color: "#5B4B3F" }}
                              >
                                {programaItem.resumen.promedio}% promedio
                              </span>
                            </div>
                          </div>
                        </summary>

                        <div className="border-t" style={{ borderColor: "rgba(212,196,176,0.6)" }}>
                          {programaItem.obras.map((obra, index) => (
                            <div
                              key={getObraKey(obra, index)}
                              className="px-4 py-4 grid gap-3 lg:grid-cols-[minmax(0,1.7fr)_minmax(180px,0.8fr)_auto] lg:items-center"
                              style={{ borderBottom: "1px solid rgba(212,196,176,0.35)" }}
                            >
                              <div className="min-w-0">
                                <p className="font-medium text-sm leading-tight" style={{ color: "#2C2C2C" }}>
                                  {obra.nombre || "SIN NOMBRE"}
                                </p>
                                <div className="flex flex-wrap gap-x-4 gap-y-1 mt-2 text-xs" style={{ color: "#666666" }}>
                                  <span>{obra.direccion_general || "SIN DIRECCION"}</span>
                                  <span>{formatearFechaHora(obra.ultimaActualizacion)}</span>
                                </div>
                              </div>

                              <div className="flex flex-col gap-2">
                                <BadgeEstado estado={obra.estado} />
                                <BarraPct pct={Number(obra.porcentaje || 0)} />
                              </div>

                              <div className="flex items-center justify-start lg:justify-end">
                                <Button
                                  size="sm"
                                  variant={obra.estado === "actualizada" ? "secondary" : "primary"}
                                  onClick={() => abrirModal(obra)}
                                  aria-label={`Actualizar ${obra.nombre}`}
                                >
                                  Actualizar
                                </Button>
                              </div>
                            </div>
                          ))}
                        </div>
                      </details>
                    ))}
                  </div>
                </details>
              ))}
            </div>
          )}
        </main>
      </div>

      <Footer />

      {obraModal && (
        <ModalActualizacion obra={obraModal} onClose={cerrarModal} />
      )}
    </div>
  );
}
